import omni.usd
from pxr import Usd, UsdGeom, UsdPhysics, UsdLux, Gf, Sdf

stage = omni.usd.get_context().get_stage()

# ── helpers ──────────────────────────────────────────────────────────────────
def xf_set(prim, pos=None, rot=None, scale=None):
    """Clear xformOps and set translate / rotateXYZ / scale cleanly."""
    xf = UsdGeom.Xformable(prim)
    xf.ClearXformOpOrder()
    if pos   is not None: xf.AddTranslateOp().Set(Gf.Vec3d(*pos))
    if rot   is not None: xf.AddRotateXYZOp().Set(Gf.Vec3f(*rot))
    if scale is not None: xf.AddScaleOp().Set(Gf.Vec3f(*scale))

def make_cube(path, pos, scale, color, collider=True, rigid=False):
    p = stage.DefinePrim(path, "Cube")
    xf_set(p, pos=pos, scale=scale)
    UsdGeom.Gprim(p).CreateDisplayColorAttr([Gf.Vec3f(*color)])
    if collider: UsdPhysics.CollisionAPI.Apply(p)
    if rigid:
        UsdPhysics.RigidBodyAPI.Apply(p)
        UsdPhysics.MassAPI.Apply(p)
    return p

def make_sphere(path, pos, radius, color, collider=True, rigid=False):
    p = stage.DefinePrim(path, "Sphere")
    p.GetAttribute("radius").Set(radius)
    xf_set(p, pos=pos)
    UsdGeom.Gprim(p).CreateDisplayColorAttr([Gf.Vec3f(*color)])
    if collider: UsdPhysics.CollisionAPI.Apply(p)
    if rigid:
        UsdPhysics.RigidBodyAPI.Apply(p)
        UsdPhysics.MassAPI.Apply(p)
    return p

